(window.webpackJsonp=window.webpackJsonp||[]).push([[7],{"5Epl":function(a,e,i){"use strict";i.d(e,"a",(function(){return j}));var o=i("q1tI"),n=i.n(o),r=i("R/WZ"),t=i("ofer"),l=Object(r.a)({figure:{margin:"0"},image:{width:"100%",maxHeight:"700px",borderRadius:"7px",display:"block",margin:"auto"}});function j(a){var e=a.src,i=a.caption,o=a.center,r=l();return n.a.createElement("figure",{className:r.figure},n.a.createElement("img",{src:e,alt:i,className:r.image,style:o?{width:"auto",margin:"auto"}:null}),n.a.createElement(t.a,{variant:"caption",paragraph:!0,align:o?"center":"left"},i))}},Ba9z:function(a,e,i){a.exports=i.p+"static/ograja-a09cb52baa59c28fe9026e263eb2c8e9.jpg"},GKiD:function(a,e,i){a.exports=i.p+"static/jamar-18c7a97a8c1c7c0afed2727efdbfb2bd.jpg"},rGlK:function(a,e,i){a.exports=i.p+"static/načrt-5583c6c5749f62dce4853d6032df032b.jpg"},vjS4:function(a,e,i){"use strict";i.r(e);var o=i("q1tI"),n=i.n(o),r=i("ofer"),t=i("mc/u"),l=i("5Epl"),j=i("GKiD"),s=i.n(j),d=i("rGlK"),v=i.n(d),k=i("Ba9z"),m=i.n(k);e.default=function(){return n.a.createElement(t.a,{title:"Cvingerska jama"},n.a.createElement(r.a,{variant:"body1",paragraph:!0},"Dolenjski griči in hribi so na široko posejani s prazgodovinskimi gradišči. Cvingersko med vsemi izstopa po tem, da se na najvišji točki, ki je skorajda v središču gradišča, nahaja kraško brezno Cvingerska (tudi Keltska) jama. Ali je bila znana že v halštatski dobi, ali se je morda odprla pozneje, pa je uganka, ki so jo med večletnimi raziskavami poskušali družno razrešiti arheologi in novomeški jamarji."),n.a.createElement(l.a,{src:m.a,caption:"Zaščitna ograja okoli vhodnega brezna Cvingerske jame."}),n.a.createElement(r.a,{variant:"body1",paragraph:!0},"Verjetno je prav lega jame v bližini obljudenih krajev spodbudila domišljijo nekaterih piscev iz začetka 20. stoletja, da so jami namenili vsak po nekaj vrstic. Najstarejši znani zapis o njej najdemo v drobni knjižici Zdravišče Toplice, ki jo je leta 1900 spisal Pavel Zhuber pl. Okrog. V poglavju Okolica zdravišča je navedel: »Takoj za parkom vzdiguje se polagoma že prej imenovani hrib Tabor. Od ceste peljejo lepe gozdne poti in stezice med gostimi, visokimi smrekami proti vrhu k nekdanji keltiški naselbini. Prav na vrhu je nad 20 metrov globoka navpična jama. Zaradi nevarnega vhoda do sedaj nihče še ni preiskal te jame, vendar pa se sodi, da so s to navpično jamo v zvezi še druge vodoravne votline. V tej jami so prav lepi kapniki.« Slabo desetletje pozneje (1909) je že omenjeni Alfons Müllner objavil knjigo o zgodovini železa, v kateri je na kratko opisal svoj obisk (1873) prazgodovinskega obzidja in gomil, ter jo opremil z risbama – na prvi je označil zemljepisno lego Cvingerja, na drugi je risbi obzidja dodal še prerez naselja, sredi katerega je dobro vidno brezno. Na naslednjo pisno obravnavo je jama čakala vse do leta 1991, ko je domačin Andrej Hudoklin v prispevku za Naše jame objavil kratek pregled do tedaj znanega dogajanja z obravnavano jamo. Ena izmed njegovih ugotovitev je bila, da je nasutje v jami nastalo po drugi svetovni vojni, kar so potrdili tudi ostanki eksplodiranih minskih teles. Ob tem je zabeležil tudi pripovedi, ki so o jami in njenih skrivnostih krožile med domačini."),n.a.createElement(r.a,{variant:"body1",paragraph:!0},"Cvingersko jamo so uradno prvi obiskali topliški jamarji, sicer člani Jamarskega kluba Novo mesto (1982). Za trikotnim vhodom (2 × 2,5 m) so izmerili 6 m globoko in 10 m dolgo vhodno brezno, v katerem pa zaradi očitnega nasutja z vrha ni bilo nadaljevanja. Ker je bila njena bližnja in širša okolica več stoletij obljudena, bi lahko v jamo po naključju (ali namerno) padli tudi razni predmeti iz različnih zgodovinskih obdobij. Zaradi svoje specifične lege je bil jami torej pripisan visok arheološki potencial. Med letoma 1986 in 1987 so se zato tudi jamarji vključili v arheološke raziskave, ki jih je takrat na Cvingerju vodil Borut Križ. V teh dveh poletnih sezonah so odkopavali nasutje, ki je domnevno prekrivalo arheološke plasti in ki je hkrati zapiralo prehod v nižje dele jame. Iz jame so s pomočjo vrvne tehnike izvlekli okoli 10 m3 materiala (zemlja, kamenje, komunalni odpadki), s čimer so jamo poglobili za več metrov. Ker so večje skale, ki jih niso mogli izvleči, začele groziti s podorom, so s kopanjem v jami prenehali. Prehod v morebitno jamsko nadaljevanje ali dostop do arheoloških plasti je zato tudi po zaključenih raziskavah ostal neznanka."),n.a.createElement(r.a,{variant:"body1",paragraph:!0},"Delo v jami je zastalo za natanko tri desetletja, dokler niso jamarji dobili vnovičnega povabila arheološke raziskovalne ekipe pod vodstvom dr. Matije Črešnarja (Oddelek za arheologijo, Filozofska fakulteta, UL), da bi s čiščenjem nasipnega stožca pod jamskim vhodom nadaljevali. Kopači v jami so nasutje nalagali v plastične sode, od koder so jih z električnim vitlom dvigovali ter po horizontalni žičnici odvlekli na petnajst metrov oddaljeno deponijo za arheološki pregled. Na več akcijah v letih 2016 in 2017 so izvlekli novih 10 m3 materiala in jamo poglobili do te mere, da se je ob jamski steni na dveh mestih odprlo nadaljevanje. Jamarske raziskave so nato pokazale, da se brezno med razvejanimi korozijskimi razpokami in manjšimi dvoranami v več stopnjah nadaljuje. Največji notranji prostor je Dvorana balvanov, ki je visoka 15 m. Na njenem dnu je splet stranskih rovov in prehodov, ki se vsi po vrsti zaprejo z neprehodnimi ožinami. Novoodkriti deli se zaključijo v jašku dobrih 10 m pod podornimi bloki omenjene dvorane na globini 51 m."),n.a.createElement(l.a,{src:v.a,caption:"Načrt Cvingerske jame. Načrt Tomaž Grdin.",center:!0}),n.a.createElement(r.a,{variant:"body1",paragraph:!0},"Po zaključenih raziskavah se je pokazalo, da v arheološkem pogledu jama ni izpolnila pričakovanj. Med izkopanim nasutjem je v množici novodobnih predmetov izstopal le zajeten kos prazgodovinske keramike, ki je bil nekoč del ostenja posode za kuhanje na ognju. Kulturnih plasti v novoodkritih delih jame ni bilo, saj so bili doslej človeku očito nedostopni. Odsotnost najdb si strokovnjaki razlagajo s tem, da je bil vhod v jamo v času poselitve gradišča zakrit oziroma zadelan. Enako verjetna je razlaga, da se je z zrušenjem jamskega stropa odprl šele po tem, ko je prazgodovinska skupnost naselje že opustila."),n.a.createElement(l.a,{src:s.a,caption:"Jamarsko prodiranje skozi ožino v Meniški dvoranici."}))}}}]);
